sparql_query:
PREFIX goo:        <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:       <http://example.org/resource#>
PREFIX xsd:        <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:        <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:       <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?county ?sviRecord ?sviYear ?sviScore ?thunderstormWindEvent ?thunderstormWindType ?thunderstormWindStart ?thunderstormWindEnd ?floodEvent ?floodType ?floodStart ?floodEnd
WHERE {
  ?county a goo:County .
  ?sviRecord a goo:SVIRecord ;
             goo:representsCounty ?county ;
             goo:sviYear ?sviYear ;
             goo:sviOverallScore ?sviScore .
  FILTER (?sviYear = 2010)
  FILTER (?sviScore >= 0.75)

  ?thunderstormWindEvent a goo:StormEventRecord ;
                         goo:occurredInCounty ?county ;
                         goo:stormEventType ?thunderstormWindType ;
                         goo:eventStartTime ?thunderstormWindStart ;
                         goo:eventEndTime ?thunderstormWindEnd .
  FILTER (REGEX(STR(?thunderstormWindType), "Thunderstorm Wind", "i"))

  ?floodEvent a goo:StormEventRecord ;
              goo:occurredInCounty ?county ;
              goo:stormEventType ?floodType ;
              goo:eventStartTime ?floodStart ;
              goo:eventEndTime ?floodEnd .
  FILTER (REGEX(STR(?floodType), "Flood", "i"))

  FILTER (?thunderstormWindStart <= ?floodStart)
  FILTER ((?floodStart - ?thunderstormWindStart) <= "P5D"^^xsd:dayTimeDuration)
}
ORDER BY DESC(?sviScore) ?county ?thunderstormWindStart ?floodStart
LIMIT 10
